import { useEffect, useState, lazy, Suspense } from 'react';
import { Toaster } from 'sonner';
import { AppShell } from '../components/layout/AppShell';
import { WorkingView } from '../components/views/WorkingView';
import { ErrorBoundary } from '../components/shared/ErrorBoundary';
import { initMessengerListener, cleanupMessengerListener } from '../stores/messengerStore';
import { useUIStore } from '../stores/uiStore';

// Lazy-loaded views — only parsed when the user navigates to them
const UsageView = lazy(() => import('../components/views/UsageView').then(m => ({ default: m.UsageView })));
const CodeReviewView = lazy(() => import('../components/views/CodeReviewView').then(m => ({ default: m.CodeReviewView })));
const DoneView = lazy(() => import('../components/views/DoneView').then(m => ({ default: m.DoneView })));
const TaskDetail = lazy(() => import('../components/views/TaskDetail').then(m => ({ default: m.TaskDetail })));
const ApiKeySettings = lazy(() => import('../components/settings/ApiKeySettings').then(m => ({ default: m.ApiKeySettings })));
const GitView = lazy(() => import('../components/views/GitView').then(m => ({ default: m.GitView })));
const CodeView = lazy(() => import('../components/views/CodeView').then(m => ({ default: m.CodeView })));
const TaskApprovalView = lazy(() => import('../components/views/TaskApprovalView').then(m => ({ default: m.TaskApprovalView })));
const TerminalBottomPanel = lazy(() => import('../components/terminal/TerminalBottomPanel').then(m => ({ default: m.TerminalBottomPanel })));
import { useTaskStore } from '../stores/taskStore';
import { commands } from '../bindings';

const TOAST_STYLE = { background: '#13131f', border: '1px solid #252538', color: '#e2e8f0', fontSize: 12 } as const;

export function App() {
  const activeView = useUIStore((s) => s.activeView);
  const setActiveView = useUIStore((s) => s.setActiveView);
  const setShowSetup = useUIStore((s) => s.setShowSetup);
  const developerMode = useUIStore((s) => s.developerMode);
  const selectedTaskId = useUIStore((s) => s.selectedTaskId);
  const setSelectedTaskId = useUIStore((s) => s.setSelectedTaskId);

  useEffect(() => {
    void initMessengerListener();
    return () => cleanupMessengerListener();
  }, []);

  useEffect(() => {
    const interval = setInterval(async () => {
      commands.cleanupCompletedProcesses().catch(() => { /* fire-and-forget cleanup */ });

      // Heartbeat: ask backend which processes are actually running
      // and reconcile frontend task state
      try {
        const result = await commands.getRunningProcesses();
        if (result.status === 'ok') {
          const backendRunning = new Set(result.data);
          const taskState = useTaskStore.getState();
          const newTasks = new Map(taskState.tasks);
          let changed = false;
          for (const [id, task] of newTasks) {
            // Skip orchestration tasks — their lifecycle is managed by handleOrchEvent,
            // not by process heartbeat. The master process gets killed after decomposition
            // but the task should stay 'running' until the orchestration completes.
            if (task.role === 'master' || task.role === 'worker') continue;
            if ((task.status === 'running' || task.status === 'retrying') && !backendRunning.has(id)) {
              // Frontend thinks it's running, backend says it's not → mark failed
              newTasks.set(id, { ...task, status: 'failed' });
              changed = true;
            }
          }
          if (changed) useTaskStore.setState({ tasks: newTasks });
        }
      } catch { /* backend may not have this command yet */ }
    }, 5_000); // Every 5 seconds
    return () => clearInterval(interval);
  }, []);

  // Auto-navigate to review only when orchestration fully completes (not during reviewing)
  const orchestrationPhase = useTaskStore((s) => s.orchestrationPhase);
  useEffect(() => {
    if (orchestrationPhase === 'completed') {
      setActiveView('review');
    }
  }, [orchestrationPhase, setActiveView]);

  // Terminal panel state
  const [terminalOpen, setTerminalOpen] = useState(false);
  useEffect(() => {
    if (orchestrationPhase === 'decomposing' || orchestrationPhase === 'executing') {
      setTerminalOpen(true);
    }
  }, [orchestrationPhase]);

  // Primary view is 'kanban' internally but shows WorkingView
  const isWorkingView = activeView === 'kanban' || activeView === 'terminal';

  return (
    <>
      <Toaster
        position="bottom-right"
        toastOptions={{ style: TOAST_STYLE }}
        theme="dark"
      />
      <Suspense fallback={null}>
        <TaskApprovalView />
      </Suspense>
      <AppShell>
        <div className="flex flex-col flex-1 overflow-hidden">
          <div className="flex flex-1 overflow-hidden min-h-0">
            <div className="flex-1 overflow-hidden">
              {isWorkingView && (
                <ErrorBoundary fallbackLabel="Working view failed to load">
                  <WorkingView selectedTask={selectedTaskId} setSelectedTask={setSelectedTaskId} />
                </ErrorBoundary>
              )}
              {activeView === 'usage' && (
                <ErrorBoundary fallbackLabel="Usage view failed to load">
                  <Suspense fallback={null}><UsageView /></Suspense>
                </ErrorBoundary>
              )}
              {activeView === 'review' && (
                <ErrorBoundary fallbackLabel="Review failed to load">
                  <Suspense fallback={null}><CodeReviewView onDone={() => setActiveView('done')} /></Suspense>
                </ErrorBoundary>
              )}
              {activeView === 'done' && (
                <ErrorBoundary fallbackLabel="Done view failed to load">
                  <Suspense fallback={null}><DoneView onNew={() => { setShowSetup(true); setActiveView('kanban'); }} /></Suspense>
                </ErrorBoundary>
              )}
              {activeView === 'settings' && (
                <ErrorBoundary fallbackLabel="Settings failed to load">
                  <Suspense fallback={null}><ApiKeySettings /></Suspense>
                </ErrorBoundary>
              )}
              {activeView === 'git' && (
                <ErrorBoundary fallbackLabel="Git view failed to load">
                  <Suspense fallback={null}><GitView /></Suspense>
                </ErrorBoundary>
              )}
              {activeView === 'code' && (
                <ErrorBoundary fallbackLabel="Code view failed to load">
                  <Suspense fallback={null}><CodeView /></Suspense>
                </ErrorBoundary>
              )}
            </div>

            {isWorkingView && selectedTaskId && (
              <ErrorBoundary fallbackLabel="Task detail failed to load">
                <Suspense fallback={null}><TaskDetail taskId={selectedTaskId} onClose={() => setSelectedTaskId(null)} /></Suspense>
              </ErrorBoundary>
            )}
          </div>

          <Suspense fallback={null}>
            <TerminalBottomPanel
              open={terminalOpen}
              onToggle={() => setTerminalOpen(!terminalOpen)}
              devMode={developerMode}
            />
          </Suspense>
        </div>
      </AppShell>
    </>
  );
}

use crate::worktree::conflict;
use crate::worktree::diff;
use crate::worktree::manager::WorktreeManager;
use crate::worktree::models::{ConflictReport, WorktreeDiffReport, WorktreeEntry};

/// Create an isolated git worktree for a task.
///
/// Creates a new branch and worktree directory in a sibling `.whalecode-worktrees/` folder.
/// Returns the WorktreeEntry for frontend tracking.
#[tauri::command]
#[specta::specta]
pub async fn create_worktree(
    task_id: String,
    project_dir: String,
) -> Result<WorktreeEntry, String> {
    let project_path = super::expand_tilde(&project_dir);
    tokio::task::spawn_blocking(move || {
        let manager = WorktreeManager::new(project_path);
        manager.create_for_task(&task_id)
    })
    .await
    .map_err(|e| format!("Worktree creation task failed: {}", e))?
}

/// Check for file-level conflicts between two worktree branches.
///
/// Auto-commits any uncommitted changes in both worktrees before running
/// the three-way merge conflict detection.
#[tauri::command]
#[specta::specta]
pub async fn check_worktree_conflicts(
    project_dir: String,
    branch_a: String,
    branch_b: String,
) -> Result<ConflictReport, String> {
    let project_path = super::expand_tilde(&project_dir);
    tokio::task::spawn_blocking(move || {
        // Resolve worktree paths from branch names
        // Branches follow pattern: whalecode/task/{prefix}
        // Worktree dirs follow pattern: .whalecode-worktrees/whalecode-{prefix}
        let manager = WorktreeManager::new(project_path.clone());
        let base_dir = manager.worktree_base_dir();

        // Extract prefix from branch name to find worktree path
        let resolve_worktree_path =
            |branch: &str| -> Option<std::path::PathBuf> {
                let prefix = branch.strip_prefix("whalecode/task/")?;
                let wt_name = format!("whalecode-{}", prefix);
                let path = base_dir.join(&wt_name);
                if path.exists() {
                    Some(path)
                } else {
                    None
                }
            };

        // Auto-commit uncommitted changes in both worktrees (best-effort)
        if let Some(path_a) = resolve_worktree_path(&branch_a) {
            let _ = conflict::auto_commit_worktree(&path_a);
        }
        if let Some(path_b) = resolve_worktree_path(&branch_b) {
            let _ = conflict::auto_commit_worktree(&path_b);
        }

        // Run conflict detection
        conflict::detect_conflicts(&project_path, &branch_a, &branch_b)
    })
    .await
    .map_err(|e| format!("Conflict check task failed: {}", e))?
}

/// Generate per-file unified diffs between a worktree branch and the default branch.
///
/// Auto-commits any uncommitted changes in the worktree before generating diffs
/// to capture all tool changes.
#[tauri::command]
#[specta::specta]
pub async fn get_worktree_diff(
    project_dir: String,
    branch_name: String,
) -> Result<WorktreeDiffReport, String> {
    let project_path = super::expand_tilde(&project_dir);
    tokio::task::spawn_blocking(move || {
        // Auto-commit pending changes in the worktree before diffing
        let manager = WorktreeManager::new(project_path.clone());
        let base_dir = manager.worktree_base_dir();
        if let Some(prefix) = branch_name.strip_prefix("whalecode/task/") {
            let wt_path = base_dir.join(format!("whalecode-{}", prefix));
            if wt_path.exists() {
                let _ = conflict::auto_commit_worktree(&wt_path);
            }
        }

        diff::generate_worktree_diff(&project_path, &branch_name)
    })
    .await
    .map_err(|e| format!("Diff task failed: {}", e))?
}

/// Merge a worktree branch into the main/default branch.
///
/// SAFE-04: Pre-merge conflict gate — checks for conflicts against the default branch
/// and all other active whalecode branches before merging. If any conflicts are detected,
/// the merge is blocked and an error is returned.
#[tauri::command]
#[specta::specta]
pub async fn merge_worktree(
    project_dir: String,
    branch_name: String,
    accepted_files: Option<Vec<String>>,
) -> Result<(), String> {
    let project_path = super::expand_tilde(&project_dir);
    tokio::task::spawn_blocking(move || {
        let repo =
            git2::Repository::open(&project_path).map_err(|e| format!("Failed to open repo: {}", e))?;

        // Determine the default branch (main or master)
        let default_branch = find_default_branch(&repo)?;

        // Auto-commit any uncommitted changes in the worktree
        let manager = WorktreeManager::new(project_path.clone());
        let base_dir = manager.worktree_base_dir();
        if let Some(prefix) = branch_name.strip_prefix("whalecode/task/") {
            let wt_path = base_dir.join(format!("whalecode-{}", prefix));
            if wt_path.exists() {
                let _ = conflict::auto_commit_worktree(&wt_path);
            }
        }

        // Check conflicts against the default branch
        let report = conflict::detect_conflicts(&project_path, &branch_name, &default_branch)?;
        if report.has_conflicts {
            let files: Vec<String> = report.conflicting_files.iter().map(|f| f.path.clone()).collect();
            return Err(format!(
                "Merge blocked: conflicts with {} in files: {}",
                default_branch,
                files.join(", ")
            ));
        }

        // Check conflicts against all other active whalecode branches
        let other_branches = manager.list_worktrees()?;
        for wt_name in &other_branches {
            let prefix = wt_name.strip_prefix("whalecode-").unwrap_or(wt_name);
            let other_branch = format!("whalecode/task/{}", prefix);
            if other_branch == branch_name {
                continue; // Skip self
            }
            let report = conflict::detect_conflicts(&project_path, &branch_name, &other_branch)?;
            if report.has_conflicts {
                let files: Vec<String> = report.conflicting_files.iter().map(|f| f.path.clone()).collect();
                return Err(format!(
                    "Merge blocked: conflicts with {} in files: {}",
                    other_branch,
                    files.join(", ")
                ));
            }
        }

        // Dry-run merge check: simulate `git merge --no-commit --no-ff` to catch
        // any conflicts that the tree-level check might miss (e.g., index-level issues).
        let dry_run_conflicts = conflict::dry_run_merge_check(&project_path, &branch_name)?;
        if !dry_run_conflicts.is_empty() {
            return Err(format!(
                "Merge blocked (dry-run): conflicts detected in files: {}",
                dry_run_conflicts.join(", ")
            ));
        }

        // Choose merge strategy based on accepted_files
        if let Some(ref files) = accepted_files {
            // Selective merge: only apply accepted files
            diff::selective_merge(&project_path, &branch_name, files)?;
        } else {
            // Full fast-forward merge (original behavior)
            let branch_commit = crate::worktree::resolve_branch_commit(&repo, &branch_name)?;

            let default_ref_name = format!("refs/heads/{}", default_branch);
            let mut default_ref = repo
                .find_reference(&default_ref_name)
                .map_err(|e| format!("Failed to find ref '{}': {}", default_ref_name, e))?;

            // Check if fast-forward is possible
            let default_commit = default_ref
                .peel_to_commit()
                .map_err(|e| format!("Failed to get default branch commit: {}", e))?;

            let is_ancestor = repo
                .merge_base(default_commit.id(), branch_commit.id())
                .map(|base| base == default_commit.id())
                .unwrap_or(false);

            if !is_ancestor {
                return Err(format!(
                    "Cannot fast-forward: {} has diverged from {}",
                    default_branch, branch_name
                ));
            }

            // Fast-forward the default branch reference
            default_ref
                .set_target(
                    branch_commit.id(),
                    &format!("whalecode: merge {} into {}", branch_name, default_branch),
                )
                .map_err(|e| format!("Failed to fast-forward merge: {}", e))?;

            // Update working directory to match new HEAD
            repo.checkout_head(Some(git2::build::CheckoutBuilder::new().force()))
                .map_err(|e| format!("Failed to update working directory: {}", e))?;
        }

        // Clean up the worktree after successful merge
        if let Some(prefix) = branch_name.strip_prefix("whalecode/task/") {
            let wt_name = format!("whalecode-{}", prefix);
            let _ = manager.remove_worktree(&wt_name);
        }

        Ok(())
    })
    .await
    .map_err(|e| format!("Merge task failed: {}", e))?
}

/// Clean up stale/invalid worktrees from previous crashed sessions.
///
/// Returns the names of worktrees that were cleaned up.
#[tauri::command]
#[specta::specta]
pub async fn cleanup_worktrees(project_dir: String) -> Result<Vec<String>, String> {
    let project_path = super::expand_tilde(&project_dir);
    tokio::task::spawn_blocking(move || {
        let manager = WorktreeManager::new(project_path);
        manager.cleanup_stale_worktrees()
    })
    .await
    .map_err(|e| format!("Cleanup task failed: {}", e))?
}

/// List all active whalecode worktrees for the project.
#[tauri::command]
#[specta::specta]
pub async fn list_worktrees(project_dir: String) -> Result<Vec<String>, String> {
    let project_path = super::expand_tilde(&project_dir);
    tokio::task::spawn_blocking(move || {
        let manager = WorktreeManager::new(project_path);
        manager.list_worktrees()
    })
    .await
    .map_err(|e| format!("List task failed: {}", e))?
}

/// Find the default branch name (main or master).
fn find_default_branch(repo: &git2::Repository) -> Result<String, String> {
    if repo
        .find_branch("main", git2::BranchType::Local)
        .is_ok()
    {
        Ok("main".to_string())
    } else if repo
        .find_branch("master", git2::BranchType::Local)
        .is_ok()
    {
        Ok("master".to_string())
    } else {
        Err("Could not find default branch (main or master)".to_string())
    }
}

