};
use state::AppState;
use tauri::Manager;
use tauri_specta::collect_commands;

#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    let builder = tauri_specta::Builder::<tauri::Wry>::new().commands(collect_commands![
        start_stream,
        get_task_count,
        spawn_process,
        cancel_process,
        pause_process,
        resume_process,
        get_running_processes,
        spawn_claude_task,
        set_claude_api_key,
        has_claude_api_key,
        validate_claude_result,
        delete_claude_api_key,
        record_task_completion_cmd,
        get_recent_changes,
        get_context_summary,
        create_worktree,
        check_worktree_conflicts,
        get_worktree_diff,
        merge_worktree,
        cleanup_worktrees,
        list_worktrees,
        spawn_gemini_task,
        set_gemini_api_key,
        has_gemini_api_key,
        validate_gemini_result,
        delete_gemini_api_key,
        spawn_codex_task,
        set_codex_api_key,
        has_codex_api_key,
        validate_codex_result,
        delete_codex_api_key,
        suggest_tool,
        dispatch_task,
        dispatch_orchestrated_task,
        get_agent_context_info,
        optimize_prompt,
        send_to_process,
        cleanup_completed_processes,
        clear_orchestration_context,
        answer_user_question,
        approve_decomposition,
        reject_decomposition,
        approve_orchestration,
        detect_agents,
        fetch_agent_usage,
        git_status,
        git_stage_files,
        git_unstage_files,
        git_commit,
        git_diff_file,
        git_log,
        git_pull,
        git_push,
        list_directory,
        read_file,
        write_file,
        get_config,
        set_config,
        get_orchestration_history,
    ]);

    #[cfg(debug_assertions)]
    {
        let export_path = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("../src/bindings.ts");
        println!("Exporting bindings to: {:?}", export_path);
        builder
            .export(specta_typescript::Typescript::default(), &export_path)
            .expect("Failed to export typescript bindings");

        // Post-process: fix TAURI_CHANNEL type alias for TypeScript compatibility.
        // specta generates `export type TAURI_CHANNEL<TSend> = null` which conflicts
        // with the Channel import and causes type errors when passing Channel objects.
        if let Ok(contents) = std::fs::read_to_string(&export_path) {
            let patched = contents
                // Fix TAURI_CHANNEL type: null → actual Channel type
                .replace(
                    "export type TAURI_CHANNEL<TSend> = null",
                    "export type TAURI_CHANNEL<TSend> = TAURI_CHANNEL_IMPORT<TSend>",
                )
                // Rename Channel import to avoid name conflict with the type alias
                .replace(
                    "Channel as TAURI_CHANNEL,",
                    "Channel as TAURI_CHANNEL_IMPORT,",
                )
                // Suppress unused __makeEvents__ warning
                .replace(
                    "\nfunction __makeEvents__",
                    "\n// @ts-ignore — auto-generated by tauri-specta\nfunction __makeEvents__",
                );
            let _ = std::fs::write(&export_path, patched);
        }

        println!("Bindings exported successfully");
    }

    let invoke_handler = builder.invoke_handler();

    tauri::Builder::default()
        .manage(AppState::default())
        .plugin(tauri_plugin_opener::init())
        .plugin(tauri_plugin_dialog::init())
        .invoke_handler(invoke_handler)
        .setup(|app| {
            let app_data_dir = app.path().app_data_dir().map_err(|e| {
                Box::<dyn std::error::Error>::from(format!("Failed to get app_data_dir: {}", e))
            })?;
            let db_path =
                context::store::ContextStore::db_path_for_project(&app_data_dir, "default");
            let context_store = context::store::ContextStore::new(&db_path).map_err(|e| {
                Box::<dyn std::error::Error>::from(format!("Failed to init ContextStore: {}", e))
            })?;
            app.manage(context_store);
            Ok(())
        })
        .build(tauri::generate_context!())
        .expect("Failed to build Tauri application")
        .run(|app_handle, event| {
            if let tauri::RunEvent::Exit = event {
                println!("App exiting — killing all tracked processes");
                let state: tauri::State<AppState> = app_handle.state();
                let lock_result = state.lock();
                let mut inner = lock_result;
                for (_id, proc) in inner.processes.drain() {
                    let _ = nix::sys::signal::killpg(
                        nix::unistd::Pid::from_raw(proc.pgid),
                        nix::sys::signal::Signal::SIGKILL,
                    );
                }
            }
        });
}

import { useState, useEffect, useMemo } from 'react';
import { ask } from '@tauri-apps/plugin-dialog';
import { useWorktree } from '../../hooks/useWorktree';
import { FileDiffView } from './FileDiffView';
import type { FileDiff } from '../../bindings';

interface DiffReviewProps {
  projectDir: string;
  branchName: string;
  taskId: string;
  onClose: (action: 'merged' | 'discarded') => void;
}

/** Status icon and color for a file diff entry. */
function statusIcon(status: string): { icon: string; color: string } {
  switch (status) {
    case 'added':
      return { icon: '+', color: 'text-green-400' };
    case 'deleted':
      return { icon: 'D', color: 'text-red-400' };
    case 'renamed':
      return { icon: 'R', color: 'text-yellow-400' };
    case 'modified':
    default:
      return { icon: 'M', color: 'text-blue-400' };
  }
}

/**
 * Diff review panel with file list sidebar and unified diff viewer.
 *
 * Allows users to accept/reject individual files before merging.
 * No auto-merge -- every merge requires explicit user action.
 */
export function DiffReview({ projectDir, branchName, taskId: _taskId, onClose }: DiffReviewProps) {
  const { diffReport, loading, error, getWorktreeDiff, selectiveMerge, cleanupWorktrees } =
    useWorktree(projectDir);

  const [acceptedFiles, setAcceptedFiles] = useState<Set<string>>(new Set());
  const [selectedFile, setSelectedFile] = useState<string | null>(null);
  const [merging, setMerging] = useState(false);

  // Fetch diff on mount
  useEffect(() => {
    getWorktreeDiff(branchName);
  }, [branchName, getWorktreeDiff]);

  // Initialize acceptedFiles when diffReport arrives (default: accept all)
  useEffect(() => {
    if (diffReport?.files) {
      setAcceptedFiles(new Set(diffReport.files.map((f) => f.path)));
      if (diffReport.files.length > 0 && !selectedFile) {
        setSelectedFile(diffReport.files[0].path);
      }
    }
  }, [diffReport]); // eslint-disable-line react-hooks/exhaustive-deps

  const files = diffReport?.files ?? [];

  const selectedDiff: FileDiff | undefined = useMemo(
    () => files.find((f) => f.path === selectedFile),
    [files, selectedFile],
  );

  const acceptedCount = acceptedFiles.size;
  const rejectedCount = files.length - acceptedCount;

  const toggleFile = (path: string) => {
    setAcceptedFiles((prev) => {
      const next = new Set(prev);
      if (next.has(path)) {
        next.delete(path);
      } else {
        next.add(path);
      }
      return next;
    });
  };

  const selectAll = () => {
    setAcceptedFiles(new Set(files.map((f) => f.path)));
  };

  const deselectAll = () => {
    setAcceptedFiles(new Set());
  };

  const handleMerge = async () => {
    if (acceptedFiles.size === 0) {
      const discardAll = await ask(
        'No files are accepted. Discard all changes from this task?',
        { title: 'Discard Changes', kind: 'warning' },
      );
      if (!discardAll) return;
      await cleanupWorktrees();
      onClose('discarded');
      return;
    }

    const mergeMsg = rejectedCount > 0
      ? `Merge ${acceptedCount} file${acceptedCount !== 1 ? 's' : ''}? ${rejectedCount} file${rejectedCount !== 1 ? 's' : ''} will be discarded.`
      : `Merge ${acceptedCount} file${acceptedCount !== 1 ? 's' : ''}?`;
    const confirmed = await ask(mergeMsg, { title: 'Confirm Merge', kind: 'info' });
    if (!confirmed) return;

    setMerging(true);
    try {
      const success = await selectiveMerge(branchName, Array.from(acceptedFiles));
      onClose(success ? 'merged' : 'discarded');
    } catch {
      // selectiveMerge threw — merge genuinely failed
      onClose('discarded');
    } finally {
      setMerging(false);
    }
  };

  const handleDiscard = async () => {
    const confirmed = await ask(
      'Discard all changes from this task?',
      { title: 'Discard All Changes', kind: 'warning' },
    );
    if (!confirmed) return;

    setMerging(true);
    try {
      // Note: cleanupWorktrees only prunes stale/orphaned worktrees via cleanup_stale_worktrees().
      // The active worktree for this branch may persist until the next cleanup cycle or app restart.
      // A proper fix would expose remove_worktree(branchName) as a Tauri command.
      await cleanupWorktrees();
      onClose('discarded');
    } finally {
      setMerging(false);
    }
  };

  // Loading state
  if (loading && !diffReport) {
    return (
      <div className="flex items-center justify-center h-full text-zinc-400">
        <div className="flex items-center gap-2">
          <div className="w-4 h-4 border-2 border-zinc-500 border-t-zinc-200 rounded-full animate-spin" />
          <span className="text-sm">Loading diff...</span>
        </div>
      </div>
    );
  }

  // Error state
  if (error) {
    return (
      <div className="flex flex-col items-center justify-center h-full gap-3 text-zinc-400">
        <p className="text-sm text-red-400">{error}</p>
        <button
          onClick={() => getWorktreeDiff(branchName)}
          className="px-3 py-1.5 text-xs rounded bg-zinc-700 hover:bg-zinc-600 text-zinc-200 transition-colors"
        >
          Retry
        </button>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-zinc-950">
      {/* Header */}
      <div className="shrink-0 flex items-center justify-between px-4 py-2 border-b border-zinc-800 bg-zinc-900/60">
        <div className="flex items-center gap-2">
          <span className="text-sm font-medium text-zinc-200">Review Changes</span>
          <span className="text-xs text-zinc-500">
            {diffReport?.branch_name} &rarr; {diffReport?.default_branch}
          </span>
        </div>
        <div className="flex items-center gap-2 text-xs text-zinc-400">
          <span className="text-green-400">+{diffReport?.total_additions ?? 0}</span>
          <span className="text-red-400">-{diffReport?.total_deletions ?? 0}</span>
        </div>
      </div>

      {/* Main content */}
      <div className="flex flex-1 min-h-0">
        {/* File list sidebar */}
        <div className="w-72 shrink-0 flex flex-col border-r border-zinc-800 bg-zinc-900/40">
          {/* Select all / deselect all */}
          <div className="shrink-0 flex items-center gap-2 px-3 py-2 border-b border-zinc-800">
            <button
              onClick={selectAll}
              className="text-xs text-zinc-400 hover:text-zinc-200 transition-colors"
            >
              Select All
            </button>
            <span className="text-zinc-700">|</span>
            <button
              onClick={deselectAll}
              className="text-xs text-zinc-400 hover:text-zinc-200 transition-colors"
            >
              Deselect All
            </button>
            <span className="ml-auto text-xs text-zinc-500">
              {files.length} file{files.length !== 1 ? 's' : ''}
            </span>
          </div>

          {/* File list */}
          <div className="flex-1 overflow-y-auto">
            {files.map((file) => {
              const { icon, color } = statusIcon(file.status);
              const isSelected = selectedFile === file.path;
              const isAccepted = acceptedFiles.has(file.path);

              return (
                <div
                  key={file.path}
                  className={`flex items-center gap-2 px-3 py-1.5 cursor-pointer text-xs transition-colors ${
                    isSelected
                      ? 'bg-zinc-800 text-zinc-100'
                      : 'text-zinc-400 hover:bg-zinc-800/50 hover:text-zinc-200'
                  }`}
                  onClick={() => setSelectedFile(file.path)}
                >
                  <input
                    type="checkbox"
                    checked={isAccepted}
                    onChange={(e) => {
                      e.stopPropagation();
                      toggleFile(file.path);
                    }}
                    onClick={(e) => e.stopPropagation()}
                    className="shrink-0 rounded border-zinc-600 bg-zinc-800 text-blue-500 focus:ring-0 focus:ring-offset-0"
                  />
                  <span className={`shrink-0 font-mono font-bold ${color}`}>{icon}</span>
                  <span className="truncate flex-1" title={file.path}>
                    {file.path}
                  </span>
                  <span className="shrink-0 text-green-500">+{file.additions}</span>
                  <span className="shrink-0 text-red-500">-{file.deletions}</span>
                </div>
              );
            })}
          </div>
        </div>

        {/* Diff viewer */}
        <div className="flex-1 min-w-0">
          {selectedDiff ? (
            <FileDiffView patch={selectedDiff.patch} />
          ) : (
            <div className="flex items-center justify-center h-full text-zinc-500 text-sm">
              Select a file to view its diff
            </div>
          )}
        </div>
      </div>

      {/* Bottom bar - only shown when there are files to review */}
      {files.length > 0 && (
        <div className="shrink-0 flex items-center justify-between px-4 py-2.5 border-t border-zinc-800 bg-zinc-900/60">
          <span className="text-xs text-zinc-400">
            {acceptedCount} file{acceptedCount !== 1 ? 's' : ''} accepted
            {rejectedCount > 0 && (
              <span className="text-zinc-500">
                , {rejectedCount} rejected
              </span>
            )}
          </span>
          <div className="flex items-center gap-2">
            <button
              onClick={handleDiscard}
              disabled={merging}
              className="px-3 py-1.5 text-xs rounded bg-zinc-800 text-red-400 hover:bg-zinc-700 hover:text-red-300 disabled:opacity-50 transition-colors"
            >
              Discard All
            </button>
            <button
              onClick={handleMerge}
              disabled={merging}
              className="px-3 py-1.5 text-xs rounded bg-blue-600 text-white hover:bg-blue-500 disabled:opacity-50 transition-colors"
            >
              {merging ? 'Merging...' : 'Merge Accepted'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
